   138|      const isExpiringSoon = expiresAt > 0 && (expiresAt - Date.now()) < 120000;
   139|
   140|      if (isExpiringSoon && session.refresh_token) {
   141|        const { data: refreshed } = await supabase.auth.refreshSession();
   142|        if (refreshed?.session?.access_token) {
   143|          headers['Authorization'] = `Bearer ${refreshed.session.access_token}`;
   144|        } else {
