/**
 * IVX Project Engagement API — Instagram-Style Cards
 *
 * Handles media, likes, comments, shares, saves, and analytics
 * for project cards on both landing page and app.
 */
import { supabase } from '../lib/supabase';

const API_BASE = (process.env.EXPO_PUBLIC_RORK_API_BASE_URL || 'https://api.ivxholding.com').replace(/\/+$/, '');

// ── Types ──────────────────────────────────────────────────────────────────

export interface ProjectMedia {
  id: string;
  project_id: string;
  media_type: 'image' | 'video';
  url: string;
  thumbnail_url: string | null;
  cover_image_url: string | null;
  title: string | null;
  description: string | null;
  duration_sec: number | null;
  width: number | null;
  height: number | null;
  file_size_bytes: number | null;
  position: number;
  is_pinned: boolean;
  is_approved: boolean;
  created_at: string;
}

export interface ProjectVideo {
  id: string;
  project_id: string;
  media_id: string | null;
  title: string | null;
  video_url: string;
  thumbnail_url: string | null;
  cover_url: string | null;
  duration_sec: number;
  width: number | null;
  height: number | null;
  orientation: 'portrait' | 'landscape' | 'square';
  is_pinned: boolean;
  is_approved: boolean;
  view_count: number;
  created_at: string;
}

export interface ProjectLike {
  id: string;
  project_id: string;
  user_id: string | null;
  guest_id: string | null;
  created_at: string;
}

export interface ProjectComment {
  id: string;
  project_id: string;
  user_id: string | null;
  guest_name: string | null;
  parent_id: string | null;
  body: string;
  is_approved: boolean;
  is_owner_reply: boolean;
  deleted_at: string | null;
  created_at: string;
  replies?: ProjectComment[];
  user_name?: string;
}

export interface ProjectShare {
  id: string;
  project_id: string;
  share_type: 'copy_link' | 'whatsapp' | 'sms' | 'email' | 'social' | 'referral' | 'other';
  created_at: string;
}

export interface ProjectSave {
  id: string;
  project_id: string;
  created_at: string;
}

export interface ProjectEngagement {
  like_count: number;
  comment_count: number;
  share_count: number;
  save_count: number;
  user_liked: boolean;
  user_saved: boolean;
}

export interface ProjectAnalytics {
  project_id: string;
  date: string;
  video_views: number;
  total_watch_sec: number;
  like_count: number;
  comment_count: number;
  share_count: number;
  save_count: number;
  invest_clicks: number;
  lead_conversions: number;
  detail_views: number;
}

export interface MediaUploadResult {
  success: boolean;
  media?: ProjectMedia;
  video?: ProjectVideo;
  error?: string;
}

// ── Helpers ────────────────────────────────────────────────────────────────

function getAuthHeaders(): Record<string, string> {
  return {
    'Content-Type': 'application/json',
    'apikey': (process.env.EXPO_PUBLIC_SUPABASE_ANON_KEY || '').trim(),
  };
}

async function apiFetch<T>(path: string, options: RequestInit = {}): Promise<T> {
  const url = `${API_BASE}${path}`;
  const res = await fetch(url, {
    ...options,
    headers: { ...getAuthHeaders(), ...(options.headers as Record<string, string> || {}) },
  });
  if (!res.ok) {
    const body = await res.text();
    throw new Error(`API ${res.status}: ${body.slice(0, 200)}`);
  }
  return res.json() as Promise<T>;
}

// ── Media ──────────────────────────────────────────────────────────────────

export async function fetchProjectMedia(projectId: string): Promise<{ images: ProjectMedia[]; videos: ProjectVideo[] }> {
  const { data: media } = await supabase
    .from('project_media')
    .select('*')
    .eq('project_id', projectId)
    .eq('is_approved', true)
    .order('position', { ascending: true });

  const { data: videos } = await supabase
    .from('project_videos')
    .select('*')
    .eq('project_id', projectId)
    .eq('is_approved', true)
    .order('is_pinned', { ascending: false });

  const images = (media || []).filter((m: ProjectMedia) => m.media_type === 'image');
  const allVideos = (videos || []) as ProjectVideo[];

  return { images, videos: allVideos };
}

export async function uploadProjectMedia(
  projectId: string,
  fileUri: string,
  mediaType: 'image' | 'video',
  title?: string,
): Promise<MediaUploadResult> {
  try {
    const fileName = `${projectId}/${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${mediaType === 'video' ? 'mp4' : 'jpg'}`;
    const bucket = mediaType === 'video' ? 'project-videos' : 'project-photos';

    // Upload to Supabase Storage
    const response = await fetch(fileUri);
    const blob = await response.blob();

    const { data: uploadData, error: uploadError } = await supabase.storage
      .from(bucket)
