  Share as RNShare,
  Platform,
} from 'react-native';
import {
  X,
  Link,
  MessageCircle,
  Smartphone,
  Mail,
  Share2,
  Users,
  Copy,
  Check,
} from 'lucide-react-native';
import * as Clipboard from 'expo-clipboard';
import * as Haptics from 'expo-haptics';
import Colors from '@/constants/colors';

const GOLD = '#FFD700';
const SURFACE = '#141414';
const SURFACE_ELEVATED = '#1A1A1A';
const BORDER = '#2A2A2A';

interface ShareOption {
  id: string;
  label: string;
  icon: React.ElementType;
  color: string;
  action: () => void;
}

interface ShareSheetProps {
  projectId: string;
  projectTitle: string;
  projectUrl: string;
  visible: boolean;
  onClose: () => void;
  onShareTrack: (projectId: string, shareType: string) => void;
}

const ProjectShareSheet = memo(function ProjectShareSheet({
  projectId,
  projectTitle,
  projectUrl,
  visible,
  onClose,
  onShareTrack,
}: ShareSheetProps) {
  const { height: windowHeight } = useWindowDimensions();
  const slideAnim = useRef(new Animated.Value(windowHeight)).current;
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    Animated.spring(slideAnim, {
      toValue: visible ? 0 : windowHeight,
      tension: 80,
      friction: 12,
      useNativeDriver: true,
    }).start();
  }, [visible, slideAnim, windowHeight]);

  useEffect(() => {
    if (!visible) setCopied(false);
  }, [visible]);

  const trackAndExecute = useCallback(
    (shareType: string, action: () => void) => {
      void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
      onShareTrack(projectId, shareType);
      action();
    },
    [projectId, onShareTrack],
  );

  const handleCopyLink = useCallback(async () => {
    await Clipboard.setStringAsync(projectUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }, [projectUrl]);

  const handleNativeShare = useCallback(async () => {
    try {
      await RNShare.share({
        message: `Check out this investment opportunity on IVX: ${projectTitle}\n${projectUrl}`,
        url: projectUrl,
        title: projectTitle,
      }, {
        dialogTitle: `Share ${projectTitle}`,
      });
    } catch {}
  }, [projectTitle, projectUrl]);

  const shareOptions: ShareOption[] = [
    {
      id: 'copy_link',
      label: 'Copy Link',
      icon: copied ? Check : Link,
      color: '#448AFF',
      action: () => trackAndExecute('copy_link', handleCopyLink),
    },
    {
      id: 'whatsapp',
      label: 'WhatsApp',
      icon: MessageCircle,
      color: '#25D366',
      action: () => trackAndExecute('whatsapp', () => {
        // WhatsApp deep link
        const text = encodeURIComponent(`Check out ${projectTitle} on IVX: ${projectUrl}`);
        const url = `whatsapp://send?text=${text}`;
        // Falls back to native share if WhatsApp not installed
        RNShare.share({ message: `Check out ${projectTitle}: ${projectUrl}`, url: projectUrl }).catch(() => {});
      }),
    },
    {
      id: 'sms',
      label: 'SMS',
      icon: Smartphone,
      color: '#00E676',
      action: () => trackAndExecute('sms', () => {
        const text = encodeURIComponent(`Check out ${projectTitle} on IVX: ${projectUrl}`);
        Platform.OS === 'web'
          ? handleCopyLink()
          : RNShare.share({ message: `Check out ${projectTitle}: ${projectUrl}`, url: projectUrl }).catch(() => {});
      }),
    },
    {
      id: 'email',
      label: 'Email',
      icon: Mail,
      color: '#EA4335',
      action: () => trackAndExecute('email', () => {
        const subject = encodeURIComponent(`Investment Opportunity: ${projectTitle}`);
        const body = encodeURIComponent(`I found this investment opportunity on IVX:\n\n${projectTitle}\n${projectUrl}\n\nCheck it out!`);
        Platform.OS === 'web'
          ? window.open(`mailto:?subject=${subject}&body=${body}`, '_blank')
          : RNShare.share({ message: `Check out ${projectTitle}: ${projectUrl}`, url: projectUrl }).catch(() => {});
      }),
    },
    {
      id: 'social',
      label: 'Share',
      icon: Share2,
      color: '#E1306C',
      action: () => trackAndExecute('social', handleNativeShare),
    },
    {
      id: 'referral',
      label: 'Referral Link',
      icon: Users,
      color: GOLD,
      action: () => trackAndExecute('referral', handleCopyLink),
    },
  ];

  if (!visible) return null;

  return (
    <Animated.View style={[styles.overlay, { transform: [{ translateY: slideAnim }] }]}>
      <View style={styles.sheet}>
        {/* Header */}
        <View style={styles.header}>
          <Text style={styles.headerTitle}>Share</Text>
          <TouchableOpacity onPress={onClose} hitSlop={12} testID="close-share">
            <X size={22} color={Colors.textSecondary} />
          </TouchableOpacity>
        </View>

        {/* Project Info */}
        <View style={styles.projectInfo}>
          <Text style={styles.projectTitle} numberOfLines={2}>
            {projectTitle}
          </Text>
          <Text style={styles.projectUrl} numberOfLines={1}>
            {projectUrl}
          </Text>
        </View>

        {/* Share Options Grid */}
        <View style={styles.optionsGrid}>
          {shareOptions.map((option) => (
            <TouchableOpacity
              key={option.id}
              style={styles.optionItem}
              onPress={option.action}
              activeOpacity={0.7}
              testID={`share-${option.id}`}
            >
              <View style={[styles.optionIconWrap, { backgroundColor: option.color + '15', borderColor: option.color + '30' }]}>
                <option.icon size={24} color={option.color} />
              </View>
              <Text style={styles.optionLabel}>{option.label}</Text>
            </TouchableOpacity>
          ))}
        </View>

        {/* Cancel */}
        <TouchableOpacity style={styles.cancelBtn} onPress={onClose} testID="share-cancel">
          <Text style={styles.cancelText}>Cancel</Text>
        </TouchableOpacity>
      </View>
    </Animated.View>
  );
});

export default ProjectShareSheet;

const styles = StyleSheet.create({
  overlay: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0,0,0,0.6)',
    justifyContent: 'flex-end',
    zIndex: 100,
  },
  sheet: {
    backgroundColor: SURFACE,
    borderTopLeftRadius: 24,
    borderTopRightRadius: 24,
    paddingBottom: 40,
    borderTopWidth: 1,
    borderColor: BORDER,
  },
  header: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    paddingHorizontal: 20,
    paddingVertical: 16,
    borderBottomWidth: 1,
    borderBottomColor: BORDER,
  },
  headerTitle: {
    color: Colors.text,
    fontSize: 18,
    fontWeight: '800' as const,
  },
  projectInfo: {
    paddingHorizontal: 20,
    paddingVertical: 14,
  },
  projectTitle: {
    color: Colors.text,
    fontSize: 15,
    fontWeight: '700' as const,
    marginBottom: 4,
  },
  projectUrl: {
    color: Colors.textSecondary,
    fontSize: 12,
  },
  optionsGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    paddingHorizontal: 12,
    gap: 4,
  },
  optionItem: {
    width: '33%',
    alignItems: 'center',
    paddingVertical: 14,
    gap: 8,
  },
  optionIconWrap: {
    width: 56,
    height: 56,
    borderRadius: 16,
    alignItems: 'center',
    justifyContent: 'center',
    borderWidth: 1,
  },
  optionLabel: {
    color: Colors.textSecondary,
    fontSize: 12,
    fontWeight: '600' as const,
    textAlign: 'center',
  },
  cancelBtn: {
    marginHorizontal: 20,
    marginTop: 12,
    paddingVertical: 14,
    backgroundColor: SURFACE_ELEVATED,
    borderRadius: 14,
    alignItems: 'center',
    borderWidth: 1,
    borderColor: BORDER,
  },
  cancelText: {
    color: Colors.textSecondary,
    fontSize: 15,
    fontWeight: '600' as const,
  },
});
"}

input.content:
/**
 * InstagramProjectCard — Video-Enabled Project Card with Instagram-Style Engagement
 *
 * Wraps TrustDealCard with:
 * - Video hero section (auto-play muted, tap to expand)
 * - Engagement bar (like, comment, share, save)
 * - Fetches engagement data from project_engagement view
 */
import React, { memo, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  NativeSyntheticEvent,
  NativeScrollEvent,
  Animated,
  ActivityIndicator,
  Platform,
} from 'react-native';
import { Video, type AVPlaybackStatus } from 'expo-av';
import {
  Play,
  Pause,
  Volume2,
  VolumeX,
  ChevronRight,
  MapPin,
  Maximize2,
} from 'lucide-react-native';
import * as Haptics from 'expo-haptics';
import Colors from '@/constants/colors';
import { formatCurrencyCompact, formatCurrencyWithDecimals } from '@/lib/formatters';
import { buildOwnershipSnapshot } from '@/lib/ownership-math';
import type { ParsedJVDeal } from '@/lib/parse-deal';
import {
  type ProjectEngagement,
  type ProjectVideo,
  type ProjectMedia,
  getProjectEngagement,
  toggleProjectLike,
  toggleProjectSave,
  trackProjectShare,
  fetchProjectMedia,
  trackVideoView,
  trackInvestClick,
} from '@/lib/project-engagement';
import ProjectEngagementBar from './ProjectEngagementBar';
import ProjectCommentsSheet from './ProjectCommentsSheet';
import ProjectShareSheet from './ProjectShareSheet';
import {
  fetchProjectComments,
  addProjectComment,
  deleteProjectComment,
  type ProjectComment,
} from '@/lib/project-engagement';

const GOLD = '#FFD700';
const GOLD_DIM = '#C9A800';
const SURFACE_ELEVATED = '#181818';
const ACCENT_GREEN = '#00E676';

interface InstagramProjectCardProps {
  deal: ParsedJVDeal;
  userId?: string | null;
  onInvestNow: (deal: ParsedJVDeal) => void;
  onViewDetails: (deal: ParsedJVDeal) => void;
  galleryWidth?: number;
  showVideo?: boolean;
  compact?: boolean;
  light?: boolean;
}

function extractLocation(deal: ParsedJVDeal): string {
  if (deal.city && deal.state) return `${deal.city}, ${deal.state}`;
  if (deal.propertyAddress) {
    const parts = deal.propertyAddress.split(',').map(s => s.trim());
    return parts.length >= 2 ? `${parts[parts.length - 2]}, ${parts[parts.length - 1]}` : deal.propertyAddress;
  }
  return '';
}

const InstagramProjectCard = memo(function InstagramProjectCard({
  deal,
  userId,
  onInvestNow,
  onViewDetails,
  galleryWidth = 340,
  showVideo = true,
  compact = false,
  light = false,
}: InstagramProjectCardProps) {
  // Video state
  const [videos, setVideos] = useState<ProjectVideo[]>([]);
  const [activeVideoIndex, setActiveVideoIndex] = useState(0);
  const [isVideoPlaying, setIsVideoPlaying] = useState(false);
  const [isVideoMuted, setIsVideoMuted] = useState(true);
  const [videoProgress, setVideoProgress] = useState(0);
  const [isVideoFullscreen, setIsVideoFullscreen] = useState(false);
  const [watchedSeconds, setWatchedSeconds] = useState(0);
  const videoRef = useRef<Video>(null);

  // Engagement state
  const [engagement, setEngagement] = useState<ProjectEngagement>({
    like_count: 0, comment_count: 0, share_count: 0, save_count: 0,
    user_liked: false, user_saved: false,
  });
  const [comments, setComments] = useState<ProjectComment[]>([]);
  const [commentsTotal, setCommentsTotal] = useState(0);
  const [commentsLoading, setCommentsLoading] = useState(false);

  // Sheet visibility
  const [showComments, setShowComments] = useState(false);
  const [showShare, setShowShare] = useState(false);

  // Animations
  const fadeAnim = useRef(new Animated.Value(0)).current;

  const location = useMemo(() => extractLocation(deal), [deal]);
  const minInvestment = deal.trustMarket?.minInvestment || 50;
  const ownershipSnapshot = useMemo(() => buildOwnershipSnapshot(minInvestment, deal.propertyValue || deal.totalInvestment || 0), [minInvestment, deal.propertyValue, deal.totalInvestment]);

  // Fetch engagement data
  useEffect(() => {
    let cancelled = false;
    const fetchData = async () => {
      try {
        const eng = await getProjectEngagement(deal.id, userId);
        if (!cancelled) setEngagement(eng);
      } catch {}
    };
    void fetchData();
    return () => { cancelled = true; };
  }, [deal.id, userId]);

  // Fetch video data
  useEffect(() => {
    if (!showVideo) return;
    let cancelled = false;
    const fetchVideos = async () => {
      try {
        const { videos: vidList } = await fetchProjectMedia(deal.id);
        if (!cancelled) setVideos(vidList);
      } catch {}
    };
    void fetchVideos();
    return () => { cancelled = true; };
  }, [deal.id, showVideo]);

  // Fade in
  useEffect(() => {
    Animated.timing(fadeAnim, { toValue: 1, duration: 400, useNativeDriver: true }).start();
  }, [fadeAnim]);

  // ── Handlers ──────────────────────────────────────────────────────────

  const handleLike = useCallback(async (projectId: string) => {
    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    try {
      const result = await toggleProjectLike(projectId, userId);
      setEngagement(prev => ({
        ...prev,
        like_count: result.likeCount,
        user_liked: result.liked,
      }));
    } catch {}
  }, [userId]);

  const handleSave = useCallback(async (projectId: string) => {
    if (!userId) return;
    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    try {
      const result = await toggleProjectSave(projectId, userId);
      setEngagement(prev => ({
        ...prev,
        save_count: result.saveCount,
        user_saved: result.saved,
      }));
    } catch {}
  }, [userId]);

  const handleComment = useCallback(async (projectId: string) => {
    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    setCommentsLoading(true);
    setShowComments(true);
    try {
      const { comments: cmts, total } = await fetchProjectComments(projectId, 20, 0);
      setComments(cmts);
      setCommentsTotal(total);
    } catch {} finally {
      setCommentsLoading(false);
    }
  }, []);

  const handleShare = useCallback((projectId: string) => {
    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    setShowShare(true);
  }, []);

  const handleAddComment = useCallback(async (projectId: string, body: string, parentId?: string) => {
    try {
      await addProjectComment(projectId, body, userId, undefined, parentId);
      const { comments: cmts, total } = await fetchProjectComments(projectId, 20, 0);
      setComments(cmts);
      setCommentsTotal(total);
      setEngagement(prev => ({ ...prev, comment_count: total }));
    } catch {}
  }, [userId]);

  const handleDeleteComment = useCallback(async (commentId: string) => {
    try {
      await deleteProjectComment(commentId);
      const { comments: cmts, total } = await fetchProjectComments(deal.id, 20, 0);
      setComments(cmts);
      setCommentsTotal(total);
      setEngagement(prev => ({ ...prev, comment_count: total }));
    } catch {}
  }, [deal.id]);

  const handleShareTrack = useCallback(async (projectId: string, shareType: string) => {
    try {
      const result = await trackProjectShare(projectId, shareType as any, userId);
      setEngagement(prev => ({ ...prev, share_count: result.shareCount }));
    } catch {}
  }, [userId]);

  const handleInvestNow = useCallback(() => {
    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Heavy);
    void trackInvestClick(deal.id);
    onInvestNow(deal);
  }, [deal, onInvestNow]);

  const handleVideoPlaybackStatus = useCallback((status: AVPlaybackStatus) => {
    if (!status.isLoaded) return;
    setIsVideoPlaying(status.isPlaying);
    if (status.durationMillis && status.positionMillis) {
      setVideoProgress(status.positionMillis / status.durationMillis);
      if (status.isPlaying) {
        setWatchedSeconds(prev => {
          const newVal = prev + 0.5;
          if (newVal >= 5 && prev < 5) {
            void trackVideoView(deal.id, newVal);
          }
          return newVal;
        });
      }
    }
  }, [deal.id]);

  const togglePlayPause = useCallback(async () => {
    if (!videoRef.current) return;
    const status = await videoRef.current.getStatusAsync();
    if (!status.isLoaded) return;
    if (status.isPlaying) {
      await videoRef.current.pauseAsync();
    } else {
      await videoRef.current.playAsync();
    }
  }, []);

  const toggleMute = useCallback(async () => {
    if (!videoRef.current) return;
    const next = !isVideoMuted;
    await videoRef.current.setIsMutedAsync(next);
    setIsVideoMuted(next);
  }, [isVideoMuted]);

  const hasVideo = videos.length > 0 && showVideo;
  const activeVideo = hasVideo ? videos[activeVideoIndex] : null;
  const shareUrl = `https://ivxholding.com/invest/${deal.id}`;

  return (
    <Animated.View style={[styles.card, { opacity: fadeAnim }]}>
      {/* ── Video Hero ─────────────────────────────────────────────────── */}
      {hasVideo && activeVideo && (
        <View style={[styles.videoContainer, { height: compact ? 200 : 260 }]}>
          <TouchableOpacity
            activeOpacity={0.95}
            onPress={togglePlayPause}
            style={styles.videoTouchArea}
          >
            <Video
              ref={videoRef}
              source={{ uri: activeVideo.video_url }}
              style={[styles.video, { height: compact ? 200 : 260 }]}
              resizeMode="cover"
              isMuted={isVideoMuted}
              shouldPlay={false}
              isLooping
              onPlaybackStatusUpdate={handleVideoPlaybackStatus}
              progressUpdateIntervalMillis={500}
            />
          </TouchableOpacity>

          {/* Video overlay controls */}
          <View style={styles.videoOverlay}>
            {/* Progress bar */}
            <View style={styles.progressBar}>
              <View style={[styles.progressFill, { width: `${videoProgress * 100}%` }]} />
            </View>

            {/* Controls row */}
            <View style={styles.videoControlsRow}>
              <TouchableOpacity onPress={togglePlayPause} style={styles.videoControlBtn}>
                {isVideoPlaying ? (
                  <Pause size={18} color="#fff" />
                ) : (
                  <Play size={18} color="#fff" />
                )}
              </TouchableOpacity>

              <TouchableOpacity onPress={toggleMute} style={styles.videoControlBtn}>
                {isVideoMuted ? (
                  <VolumeX size={18} color="#fff" />
                ) : (
                  <Volume2 size={18} color="#fff" />
                )}
              </TouchableOpacity>

              <View style={styles.videoControlSpacer} />

              {/* Video dots */}
              {videos.length > 1 && (
                <View style={styles.videoDotsRow}>
                  {videos.map((_, idx) => (
                    <View
                      key={idx}
                      style={[
                        styles.videoDot,
                        idx === activeVideoIndex && styles.videoDotActive,
                      ]}
                    />
                  ))}
                </View>
              )}

              <TouchableOpacity
                style={styles.videoControlBtn}
                onPress={() => {
                  setActiveVideoIndex((prev) => (prev + 1) % videos.length);
                  setVideoProgress(0);
                }}
              >
                <ChevronRight size={18} color="#fff" />
              </TouchableOpacity>
            </View>

            {/* Badges */}
            <View style={styles.videoBadges}>
              <View style={styles.liveBadge}>
                <View style={styles.liveDot} />
                <Text style={styles.liveBadgeText}>LIVE</Text>
              </View>
              {activeVideo.duration_sec > 0 && (
                <View style={styles.durationBadge}>
                  <Text style={styles.durationText}>
                    {Math.floor(activeVideo.duration_sec / 60)}:{String(Math.floor(activeVideo.duration_sec % 60)).padStart(2, '0')}
                  </Text>
                </View>
              )}
            </View>
          </View>

          {/* Center play button */}
          {!isVideoPlaying && (
            <TouchableOpacity
              style={styles.centerPlayBtn}
              onPress={togglePlayPause}
              activeOpacity={0.8}
            >
              <View style={styles.centerPlayCircle}>
                <Play size={28} color="#000" fill="#000" />
              </View>
            </TouchableOpacity>
          )}
        </View>
      )}

      {/* ── Engagement Bar ─────────────────────────────────────────────── */}
      <ProjectEngagementBar
        projectId={deal.id}
        likeCount={engagement.like_count}
        commentCount={engagement.comment_count}
        shareCount={engagement.share_count}
        saveCount={engagement.save_count}
        isLiked={engagement.user_liked}
        isSaved={engagement.user_saved}
        onLikePress={handleLike}
        onCommentPress={handleComment}
        onSharePress={handleShare}
        onSavePress={handleSave}
        compact={compact}
        light={light}
      />

      {/* ── Deal Info ──────────────────────────────────────────────────── */}
      <TouchableOpacity
        style={styles.dealInfoSection}
        onPress={() => onViewDetails(deal)}
        activeOpacity={0.85}
      >
        {/* Location + Title */}
        <View style={styles.dealHeader}>
          <Text style={styles.dealTitle} numberOfLines={2}>
            {deal.title || deal.projectName}
          </Text>
          {location ? (
            <View style={styles.locationRow}>
              <MapPin size={12} color={Colors.textTertiary} />
              <Text style={styles.locationText}>{location}</Text>
            </View>
          ) : null}
        </View>

        {/* Key Metrics */}
        <View style={styles.metricsRow}>
          <View style={styles.metric}>
            <Text style={styles.metricValue}>
              {formatCurrencyCompact(deal.totalInvestment || 0)}
            </Text>
            <Text style={styles.metricLabel}>Investment</Text>
          </View>
          <View style={styles.metricDivider} />
          <View style={styles.metric}>
            <Text style={[styles.metricValue, styles.metricHighlight]}>
              {deal.expectedROI}%
            </Text>
            <Text style={styles.metricLabel}>Target ROI</Text>
          </View>
          <View style={styles.metricDivider} />
          <View style={styles.metric}>
            <Text style={styles.metricValue}>
              {formatCurrencyWithDecimals(minInvestment)}
            </Text>
            <Text style={styles.metricLabel}>Min Investment</Text>
          </View>
        </View>

        {/* Ownership hint */}
        <Text style={styles.ownershipHint}>{ownershipSnapshot.ownershipText}</Text>
      </TouchableOpacity>

      {/* ── CTA Buttons ────────────────────────────────────────────────── */}
      <View style={styles.ctaRow}>
        <TouchableOpacity
          style={styles.detailsBtn}
          onPress={() => onViewDetails(deal)}
          activeOpacity={0.85}
          testID={`view-details-${deal.id}`}
        >
          <Text style={styles.detailsBtnText}>View Details</Text>
        </TouchableOpacity>
        <TouchableOpacity
          style={styles.investBtn}
          onPress={handleInvestNow}
          activeOpacity={0.85}
          testID={`invest-now-${deal.id}`}
        >
          <Text style={styles.investBtnText}>Invest Now</Text>
        </TouchableOpacity>
      </View>

      {/* ── Shets ──────────────────────────────────────────────────────── */}
      <ProjectCommentsSheet
        projectId={deal.id}
        visible={showComments}
        onClose={() => setShowComments(false)}
        comments={comments}
        isLoading={commentsLoading}
        onAddComment={handleAddComment}
        onDeleteComment={handleDeleteComment}
        totalComments={commentsTotal}
      />

      <ProjectShareSheet
        projectId={deal.id}
        projectTitle={deal.title || deal.projectName || ''}
        projectUrl={shareUrl}
        visible={showShare}
        onClose={() => setShowShare(false)}
        onShareTrack={handleShareTrack}
      />
    </Animated.View>
  );
});

export default InstagramProjectCard;

const styles = StyleSheet.create({
  card: {
    backgroundColor: '#0D0D0D',
    borderRadius: 18,
    overflow: 'hidden',
    borderWidth: 1,
    borderColor: '#222',
    marginBottom: 16,
  },
  // ── Video ──────────────────────────────────────────────────────────
  videoContainer: {
    position: 'relative',
    backgroundColor: '#000',
    overflow: 'hidden',
  },
  videoTouchArea: {
    width: '100%',
    height: '100%',
  },
  video: {
    width: '100%',
    backgroundColor: '#000',
  },
  videoOverlay: {
    position: 'absolute',
    bottom: 0,
    left: 0,
    right: 0,
    paddingBottom: 8,
  },
  progressBar: {
    height: 3,
    backgroundColor: 'rgba(255,255,255,0.2)',
    marginHorizontal: 0,
  },
  progressFill: {
    height: 3,
    backgroundColor: GOLD,
  },
  videoControlsRow: {
